import{_ as l,o as e,c as i,a3 as t}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"LLM 对话（移动端）","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/mobile/llm-chat.md","filePath":"user-guide/mobile/llm-chat.md","lastUpdated":1781934556000}'),r={name:"user-guide/mobile/llm-chat.md"};function o(h,a,n,d,s,u){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="llm-对话-移动端" tabindex="-1">LLM 对话（移动端） <a class="header-anchor" href="#llm-对话-移动端" aria-label="Permalink to &quot;LLM 对话（移动端）&quot;">​</a></h1><p>移动端 LLM 对话提供轻量的随身聊天体验：你可以新建会话、继续历史会话、发送消息、查看分支，并在独立的聊天设置页调整常用行为。</p><h2 id="进入对话" tabindex="-1">进入对话 <a class="header-anchor" href="#进入对话" aria-label="Permalink to &quot;进入对话&quot;">​</a></h2><ol><li>打开移动端首页。</li><li>点击「AI 对话」。</li><li>在入口页选择「开启新对话」或「历史会话」。</li><li>如果是新对话，系统会创建会话并进入聊天页。</li></ol><p>进入前建议先完成 <a href="./llm-api">API 配置</a>。如果没有可用渠道，发送消息时会因为缺少模型或 Key 而失败。</p><h2 id="入口页操作" tabindex="-1">入口页操作 <a class="header-anchor" href="#入口页操作" aria-label="Permalink to &quot;入口页操作&quot;">​</a></h2><p>AI 对话入口页包含：</p><ul><li>开启新对话：立即创建一个新会话。</li><li>历史会话：查看并继续已有会话。</li><li>设置按钮：进入聊天设置。</li><li>角色大厅、用户档案：当前为预留入口，后续逐步补齐。</li></ul><h2 id="发送消息" tabindex="-1">发送消息 <a class="header-anchor" href="#发送消息" aria-label="Permalink to &quot;发送消息&quot;">​</a></h2><ol><li>进入某个聊天会话。</li><li>在底部输入框输入内容。</li><li>点击发送按钮。</li><li>等待模型响应。</li></ol><p>移动端会根据键盘状态调整底部区域。输入长文本时，建议先在草稿应用中整理，再粘贴到输入框，减少误触。</p><h2 id="会话列表" tabindex="-1">会话列表 <a class="header-anchor" href="#会话列表" aria-label="Permalink to &quot;会话列表&quot;">​</a></h2><p>在入口页点击「历史会话」可以进入会话列表。这里用于继续旧对话、查找近期会话，或进入某个会话详情。</p><p>如果会话没有及时出现，返回入口页再进入会话列表，触发一次数据加载。</p><h2 id="分支与续聊" tabindex="-1">分支与续聊 <a class="header-anchor" href="#分支与续聊" aria-label="Permalink to &quot;分支与续聊&quot;">​</a></h2><p>移动端保留了会话树和分支相关的数据结构。你可以在消息操作中查看或切换可用分支；复杂的树图视图和桌面端高级操作可能尚未完整移植。</p><p>日常使用建议保持一个主分支，只有在需要尝试不同回复方向时再创建分支。</p><h2 id="聊天设置" tabindex="-1">聊天设置 <a class="header-anchor" href="#聊天设置" aria-label="Permalink to &quot;聊天设置&quot;">​</a></h2><p>点击入口页右上角的设置按钮进入聊天设置。常见设置包括：</p><ul><li>当前模型和渠道。</li><li>请求行为。</li><li>消息显示偏好。</li><li>上下文相关选项。</li></ul><p>移动端设置项会优先保留高频选项。桌面端中更复杂的 Agent、世界书、上下文管道可视化等能力，可能需要回到桌面端完成配置。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>在移动端先配置少量稳定模型，减少切换成本。</li><li>网络环境不稳定时，优先使用响应快、上下文要求低的模型。</li><li>长会话如果回复变慢，可以新建会话继续主题摘要。</li><li>出现发送失败时，先检查 LLM 服务渠道是否启用、Key 是否为空、模型是否存在。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么点击发送后没有回复" tabindex="-1">为什么点击发送后没有回复？ <a class="header-anchor" href="#为什么点击发送后没有回复" aria-label="Permalink to &quot;为什么点击发送后没有回复？&quot;">​</a></h3><p>常见原因是没有可用 LLM 渠道、API Key 为空、模型名错误或网络不可达。先到「LLM 服务」检查配置，再打开日志管理器查看错误。</p><h3 id="移动端支持桌面端-agent-吗" tabindex="-1">移动端支持桌面端 Agent 吗？ <a class="header-anchor" href="#移动端支持桌面端-agent-吗" aria-label="Permalink to &quot;移动端支持桌面端 Agent 吗？&quot;">​</a></h3><p>移动端保留部分聊天能力，但 Agent 相关复杂管理仍在逐步移植。当前以基础对话和会话继续为主。</p><h3 id="可以在移动端使用附件吗" tabindex="-1">可以在移动端使用附件吗？ <a class="header-anchor" href="#可以在移动端使用附件吗" aria-label="Permalink to &quot;可以在移动端使用附件吗？&quot;">​</a></h3><p>以当前界面实际入口为准。若没有显示附件按钮，说明该能力尚未在移动端教程主线中开放。</p><h3 id="历史会话会不会自动保存" tabindex="-1">历史会话会不会自动保存？ <a class="header-anchor" href="#历史会话会不会自动保存" aria-label="Permalink to &quot;历史会话会不会自动保存？&quot;">​</a></h3><p>会话由移动端聊天存储管理。正常发送和收到回复后会保存；异常退出前未完成的流式响应可能需要重新发送。</p>',32)])])}const m=l(r,[["render",o]]);export{p as __pageData,m as default};
